const PROCESSING_FEE = 5;
const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
const COMPONENT_BASE_PREMIUM = 25;
const BUILDING_BLOCK_SIZE = 3;
const BUILDING_BLOCK_BASE_PREMIUM = 60;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune"]);

const isComponent = (item: Item) => COMPONENT_TYPES.has(item.type);

const componentGroupBase = (count: number): number => {
  if (count === BUILDING_BLOCK_SIZE) return BUILDING_BLOCK_BASE_PREMIUM;
  return count * COMPONENT_BASE_PREMIUM;
};

const componentBaseSum = (components: Item[]): number => {
  const countsByType = new Map<string, number>();
  for (const item of components) {
    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of countsByType.values()) {
    total += componentGroupBase(count);
  }
  return total;
};

const itemBaseSum = (items: Item[]): number => {
  const mainItems = items.filter((i) => !isComponent(i));
  const components = items.filter(isComponent);
  const mainSum = mainItems.reduce((sum, item) => sum + MAIN_ITEM_BASE_PREMIUM[item.type], 0);
  return mainSum + componentBaseSum(components);
};

const quotePremium = (items: Item[]): number => {
  const base = itemBaseSum(items);
  const firstContractInsurance = base * FIRST_CONTRACT_INSURANCE_RATE;
  return Math.ceil(base + firstContractInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

