import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---- Simplest cases ----
  it("empty item list quote — premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // ---- Base premiums per item type ----
  it("single sword (no modifiers, newcomer first contract) — base 100 + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (no modifiers, newcomer first contract) — base 60 + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff (no modifiers, newcomer first contract) — base 80 + 8 first + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion (no modifiers, newcomer first contract) — base 40 + 4 first + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // ---- Components: building blocks of 3 alike ----
  it("2 runes (newcomer first contract) — base 50 + 5 first + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes (block) — base 60 + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes (no block) — base 100 + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes (no block) — base 175 + 17.5 first + 5 fee = 197.5 → 198 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // ---- Alike means same type ----
  it("2 runes + 1 moonstone (no block: different types) — base 75 + 7.5 first + 5 fee = 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones (two separate blocks) — base 120 + 12 first + 5 fee = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // ---- Modifier scope: cursed surcharge applies only to cursed item's base ----
  it("policy with cursed sword + plain amulet (newcomer) — 100 + 50 curse + 60 = 210 + 21 first + 5 fee = 236 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", cursed: true },
            { type: "amulet" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 236 }] });
  });

  // ---- Modifier thresholds ----
  it.todo("customer with exactly 2 years — loyalty discount applies");
  it.todo("sword enchantment 5 — high-enchantment surcharge applies");
  it.todo("cursed sword enchantment 5 — both curse and high-enchantment surcharges apply");
  it.todo("sword enchantment 4 — no high-enchantment surcharge");

  // ---- Integration example: newcomer cursed sword ----
  it.todo("newcomer (0 years) cursed sword enchantment 3 — premium 165 G");

  // ---- Integration example: long-standing customer second contract ----
  it.todo("long-standing customer (3 years), second contract, cursed sword enchantment 7 — premium 160 G");

  // ---- Rounding (premium up) — covered by "7 runes" test above ----

  // ---- Claim processing: simple deductible ----
  it.todo("regular sword (steel, enchantment 3), damage 500 G — payout 400 G (500 - 100 deductible)");
  it.todo("damage to a rune (insurance 250 G), damage 200 G — payout 100 G (full minus deductible)");

  // ---- Claim processing: high enchantment 50% clause ----
  it.todo("dragon-material sword enchantment 8, damage 1000 G — payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchantment 5, damage 800 G — payout 700 G (full minus deductible)");
  it.todo("steel sword enchantment 9, damage 1000 G — payout 400 G (50% then deductible)");

  // ---- Deductible per damage event (per damaged item) ----
  it.todo("dragon attack damages sword 500 + amulet 300 — payout 600 G (100 deductible per item)");

  // ---- Multiple items of the same type ----
  it.todo("policy with two swords — insurance sum 2000 G, cap 4000 G");
  it.todo("two swords, both damaged by dragon, each with own deductible");
  it.todo("damages references more items of a type than policy covers — CLI exits non-zero");

  // ---- Cap exhaustion ----
  it.todo("sword + amulet policy — insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (premium with modifiers 165 G) — cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes — insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword (cap 2000), successive claims of 1500 G — first payout 1400 (cap 600), second payout 600 (cap 0)");

  // ---- Rounding for claims ----
  it.todo("payout calculation that yields 350.5 G — rounded down to 350 G (MHPCO favor)");

  // ---- Edge cases ----
  it.todo("unknown item type in quote — CLI exits non-zero, writes error to stderr");
  it.todo("claim references item not in policy — CLI exits non-zero, writes error to stderr");
  it.todo("claim damage entry with negative amount — CLI exits non-zero, writes error to stderr");

  // ---- CLI integration ----
  it.todo("CLI reads scenario from stdin and writes results to stdout in correct order");
});

