     ```typescript
     const PROCESSING_FEE = 5;
     const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
     const LOYALTY_DISCOUNT_RATE = 0.2;
     const LOYALTY_THRESHOLD_YEARS = 2;
     const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
     const COMPONENT_BASE_PREMIUM = 25;
     const COMPONENT_INSURANCE_VALUE = 250;
     const BUILDING_BLOCK_SIZE = 3;
     const BUILDING_BLOCK_BASE_PREMIUM = 60;
     const CURSE_SURCHARGE_RATE = 0.5;
     const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
     const HIGH_ENCHANTMENT_THRESHOLD = 5;
     const DEDUCTIBLE_PER_DAMAGE = 100;
     const CAP_MULTIPLIER = 2;

     type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
     type Customer = { yearsWithMHPCO: number };
     type Damage = { itemType: string; amount: number };
     type Incident = { cause: string; damages: Damage[] };
     type QuoteStep = { op: "quote"; items: Item[] };
     type ClaimStep = { op: "claim"; policy: number; incident: Incident };
     type Step = QuoteStep | ClaimStep;
     type Scenario = { customer: Customer; steps: Step[] };

     type QuoteResult = { premium: number };
     type ClaimResult = { payout: number; remainingCap: number };
     type StepResult = QuoteResult | ClaimResult;

     const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = { sword: 100, amulet: 60, staff: 80, potion: 40 };
     const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = { sword: 1000, amulet: 600, staff: 800, potion: 400 };
     const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

     // ... helpers: isComponent, itemInsuranceValue, componentsGroupBase, itemBasePremium, itemSurcharges, sum, countByType
     // ... policyBaseSum, policyItemSurcharges, quotePremium (with isFollowUp)

     type Policy = { items: Item[]; cap: number };
     const createPolicy = (items: Item[]): Policy => {
       const insuranceSum = sum(items.map(itemInsuranceValue));
       return { items, cap: insuranceSum * CAP_MULTIPLIER };
     };
     const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
     const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
       const rawPayout = sum(incident.damages.map(damagePayout));
       const payout = Math.min(rawPayout, policy.cap);
       policy.cap -= payout;
       return { payout: Math.floor(payout), remainingCap: policy.cap };
     };

     export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
       const policies: Policy[] = [];
       let quoteCount = 0;
       const results: StepResult[] = scenario.steps.map((step) => {
         if (step.op === "quote") {
           const isFollowUp = quoteCount > 0;
           quoteCount++;
           policies.push(createPolicy(step.items));
           return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
         }
         return processClaim(policies[step.policy], step.incident);
       });
       return { results };
     };
