import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---- Simplest cases ----
  it("empty item list quote — premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // ---- Base premiums per item type ----
  it("single sword (no modifiers, newcomer first contract) — base 100 + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (no modifiers, newcomer first contract) — base 60 + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff (no modifiers, newcomer first contract) — base 80 + 8 first + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion (no modifiers, newcomer first contract) — base 40 + 4 first + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // ---- Components: building blocks of 3 alike ----
  it("2 runes (newcomer first contract) — base 50 + 5 first + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes (block) — base 60 + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes (no block) — base 100 + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes (no block) — base 175 + 17.5 first + 5 fee = 197.5 → 198 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // ---- Alike means same type ----
  it("2 runes + 1 moonstone (no block: different types) — base 75 + 7.5 first + 5 fee = 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones (two separate blocks) — base 120 + 12 first + 5 fee = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // ---- Modifier scope: cursed surcharge applies only to cursed item's base ----
  it("policy with cursed sword + plain amulet (newcomer) — 100+60 base + 50 curse + 16 first (10% of 160 base) + 5 fee = 231 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", cursed: true },
            { type: "amulet" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // ---- Modifier thresholds ----
  it("customer with exactly 2 years, plain sword (first contract) — 100 − 20 loyalty + 10 first + 5 fee = 95 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("sword enchantment 5 (newcomer) — 100 base + 30 enchantment + 10 first + 5 fee = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("cursed sword enchantment 5 (newcomer) — 100 + 50 curse + 30 enchantment + 10 first + 5 fee = 195 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });
  it("sword enchantment 4 (newcomer) — no enchantment surcharge: 100 + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });

  // ---- Integration example: newcomer cursed sword ----
  it("newcomer (0 years) cursed sword (steel, enchantment 3) — premium 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });

  // ---- Integration example: long-standing customer second contract ----
  it("long-standing customer (3 years), 2nd contract, cursed sword enchantment 7 — premium 160 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        { op: "quote", items: [{ type: "potion" }] },
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 7, cursed: true }] },
      ],
    });
    expect(result.results[1]).toEqual({ premium: 160 });
  });

  // ---- Rounding (premium up) — covered by "7 runes" test above ----

  // ---- Claim processing: simple deductible ----
  it("regular sword damage 500 G — payout 400 G, remainingCap 1600", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3 }] },
        { op: "claim", policy: 0, incident: { cause: "accident", damages: [{ itemType: "sword", amount: 500 }] } },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400, remainingCap: 1600 });
  });
  it("damage to a rune (insurance 250), damage 200 G — payout 100 G, remainingCap 1400", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
        { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "rune", amount: 200 }] } },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 100, remainingCap: 1400 });
  });

  // ---- Claim processing: high enchantment 50% clause ----
  it("dragon-material sword enchantment 8, damage 1000 — payout 400 (50% then deductible), cap 1600", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "dragon", enchantment: 8 }] },
        { op: "claim", policy: 0, incident: { cause: "dragon", damages: [{ itemType: "sword", amount: 1000 }] } },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400, remainingCap: 1600 });
  });
  it.todo("dragon-material sword enchantment 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchantment 5, damage 800 G — payout 700 G (full minus deductible)");
  it.todo("steel sword enchantment 9, damage 1000 G — payout 400 G (50% then deductible)");

  // ---- Deductible per damage event (per damaged item) ----
  it.todo("dragon attack damages sword 500 + amulet 300 — payout 600 G (100 deductible per item)");

  // ---- Multiple items of the same type ----
  it.todo("policy with two swords — insurance sum 2000 G, cap 4000 G");
  it.todo("two swords, both damaged by dragon, each with own deductible");
  it.todo("damages references more items of a type than policy covers — CLI exits non-zero");

  // ---- Cap exhaustion ----
  it.todo("sword + amulet policy — insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (premium with modifiers 165 G) — cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes — insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword (cap 2000), successive claims of 1500 G — first payout 1400 (cap 600), second payout 600 (cap 0)");

  // ---- Rounding for claims ----
  it.todo("payout calculation that yields 350.5 G — rounded down to 350 G (MHPCO favor)");

  // ---- Edge cases ----
  it.todo("unknown item type in quote — CLI exits non-zero, writes error to stderr");
  it.todo("claim references item not in policy — CLI exits non-zero, writes error to stderr");
  it.todo("claim damage entry with negative amount — CLI exits non-zero, writes error to stderr");

  // ---- CLI integration ----
  it.todo("CLI reads scenario from stdin and writes results to stdout in correct order");
});

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_INSURANCE_VALUE = 250;
const BUILDING_BLOCK_SIZE = 3;
const BUILDING_BLOCK_BASE_PREMIUM = 60;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const DEDUCTIBLE_PER_DAMAGE = 100;
const CAP_MULTIPLIER = 2;

type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
type Customer = { yearsWithMHPCO: number };
type Damage = { itemType: string; amount: number };
type Incident = { cause: string; damages: Damage[] };
type QuoteStep = { op: "quote"; items: Item[] };
type ClaimStep = { op: "claim"; policy: number; incident: Incident };
type Step = QuoteStep | ClaimStep;
type Scenario = { customer: Customer; steps: Step[] };

type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };
type StepResult = QuoteResult | ClaimResult;

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (type: string) => COMPONENT_TYPES.has(type);

const itemInsuranceValue = (item: Item): number =>
  isComponent(item.type) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INSURANCE_VALUE[item.type];

const componentsGroupBase = (count: number): number => {
  if (count === BUILDING_BLOCK_SIZE) return BUILDING_BLOCK_BASE_PREMIUM;
  return count * COMPONENT_BASE_PREMIUM;
};

const itemBasePremium = (item: Item): number => {
  if (isComponent(item.type)) return COMPONENT_BASE_PREMIUM;
  return MAIN_ITEM_BASE_PREMIUM[item.type];
};

const itemSurcharges = (item: Item): number => {
  if (isComponent(item.type)) return 0;
  const base = itemBasePremium(item);
  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
  const highEnchantment =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
      : 0;
  return curse + highEnchantment;
};

const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce((counts, item) => {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    return counts;
  }, new Map<string, number>());

const policyBaseSum = (items: Item[]): number => {
  const mainItems = items.filter((i) => !isComponent(i.type));
  const components = items.filter((i) => isComponent(i.type));
  const mainSum = sum(mainItems.map(itemBasePremium));
  const componentsSum = sum(
    Array.from(countByType(components).values(), componentsGroupBase)
  );
  return mainSum + componentsSum;
};

const policyItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));

const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
  const baseSum = policyBaseSum(items);
  const surcharges = policyItemSurcharges(items);
  const firstContractInsurance = baseSum * FIRST_CONTRACT_INSURANCE_RATE;
  const loyaltyDiscount =
    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? baseSum * LOYALTY_DISCOUNT_RATE : 0;
  const followUpDiscount = isFollowUp ? baseSum * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
  return Math.ceil(
    baseSum + surcharges + firstContractInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE
  );
};

type Policy = { items: Item[]; cap: number };

const createPolicy = (items: Item[]): Policy => {
  const insuranceSum = sum(items.map(itemInsuranceValue));
  return { items, cap: insuranceSum * CAP_MULTIPLIER };
};

const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);

const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
  const rawPayout = sum(incident.damages.map(damagePayout));
  const payout = Math.min(rawPayout, policy.cap);
  policy.cap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.cap };
};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const policies: Policy[] = [];
  let quoteCount = 0;
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount++;
      policies.push(createPolicy(step.items));
      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
    }
    return processClaim(policies[step.policy], step.incident);
  });
  return { results };
};

